#include <stdio.h>
#include <stdlib.h>

// Define the structure for a queue node
typedef struct QueueNode {
    int data;
    struct QueueNode* next;
} QueueNode;

// Define the structure for a graph node
typedef struct GraphNode {
    int data;
    struct GraphNode* next;
} GraphNode;

// Function to create a new queue node
QueueNode* createQueueNode(int data) {
    QueueNode* newNode = (QueueNode*) malloc(sizeof(QueueNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to create a new graph node
GraphNode* createGraphNode(int data) {
    GraphNode* newNode = (GraphNode*) malloc(sizeof(GraphNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to add an edge to the graph
void addEdge(GraphNode** adjList, int src, int dest, int n) {
    GraphNode* newNode = createGraphNode(dest);
    if (adjList[src] == NULL) {
        adjList[src] = newNode;
    } else {
        GraphNode* lastNode = adjList[src];
        while (lastNode->next) {
            lastNode = lastNode->next;
        }
        lastNode->next = newNode;
    }
}

// Function to perform BFS traversal
void bfs(GraphNode** adjList, int* visited, int* level, int src, int n) {
    QueueNode* queue = createQueueNode(src);
    visited[src] = 1;
    level[src] = 0;
    while (queue) {
        int currentNode = queue->data;
        GraphNode* temp = adjList[currentNode];
        while (temp) {
            if (!visited[temp->data]) {
                QueueNode* newNode = createQueueNode(temp->data);
                newNode->next = queue;
                queue = newNode;
                visited[temp->data] = 1;
                level[temp->data] = level[currentNode] + 1;
            }
            temp = temp->next;
        }
        QueueNode* tempQueue = queue;
        queue = queue->next;
        free(tempQueue);
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        GraphNode** adjList = (GraphNode**) malloc(n * sizeof(GraphNode*));
        for (int i = 0; i < n; i++) {
            adjList[i] = NULL;
        }
        for (int i = 0; i < n - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(adjList, u - 1, v - 1, n);
            addEdge(adjList, v - 1, u - 1, n);
        }
        int* visited = (int*) malloc(n * sizeof(int));
        int* level = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            visited[i] = 0;
            level[i] = -1;
        }
        bfs(adjList, visited, level, 0, n);
        for (int i = 0; i < n; i++) {
            if (level[i] == k) {
                printf("%d ", i + 1);
            }
        }
        printf("\n");
        for (int i = 0; i < n; i++) {
            GraphNode* temp = adjList[i];
            while (temp) {
                GraphNode* next = temp->next;
                free(temp);
                temp = next;
            }
        }
        free(adjList);
        free(visited);
        free(level);
    }
    return 0;
}

