void bfs(vector<vector<int>>& adjList, vector<int>& visited, vector<int>& level, int src, int n) {
    queue<int> q;
    q.push(src);
    visited[src] = 1;
    level[src] = 0;
    while (!q.empty()) {
        int currentNode = q.front();
        q.pop();
        for (int neighbor : adjList[currentNode]) {
